const gestor = $('Webhook').first().json.query?.gestor || null;

if (!$input.all() || $input.all().length === 0) {
  throw new Error('Google Sheets retornou 0 linhas — planilha vazia ou inacessível');
}

function parseBRL(value) {
  if (value === null || value === undefined || value === '') return 0;
  const str = String(value)
    .replace(/R\$\s*/g, '')
    .replace(/\./g, '')
    .replace(',', '.')
    .trim();
  const num = parseFloat(str);
  return isNaN(num) ? 0 : num;
}

const normalized = $input.all()
  .map(item => {
    const r = item.json;
    return {
      cliente:      String(r['Cliente'] ?? '').trim(),
      gestor:       String(r['Gestor'] ?? r['gestor'] ?? '').trim(),
      investimento: parseBRL(r['Total de Investimento']),
      leads:        parseBRL(r['Total de RESULTADOS (Gerenciador)']),
      metaCPA:      parseBRL(r['Meta de CPA']),
    };
  })
  .filter(r => r.cliente !== '');

const filtered = gestor
  ? normalized.filter(r => r.gestor.toLowerCase() === gestor.toLowerCase())
  : normalized;

return filtered.map(r => ({ json: r }));

// ── CACHE (TTL 2 min) ─────────────────────────────────────
const cache = $getWorkflowStaticData('global');
const CACHE_TTL = 120_000;

if (cache.payload && (Date.now() - cache.ts) < CACHE_TTL) {
  return [{ json: { ...cache.payload, fromCache: true } }];
}
// ──────────────────────────────────────────────────────────

const rows = $input.all().map(i => i.json);
const gestorFiltro = $('Webhook').first().json.query?.gestor || null;

const map = {};
for (const row of rows) {
  if (!map[row.cliente]) {
    map[row.cliente] = { cliente: row.cliente, investimento: 0, leads: 0, metaCPA: 0, _metaCount: 0 };
  }
  map[row.cliente].investimento += row.investimento;
  map[row.cliente].leads        += row.leads;
  if (row.metaCPA > 0) {
    map[row.cliente].metaCPA   += row.metaCPA;
    map[row.cliente]._metaCount++;
  }
}

const resultado = Object.values(map).map(c => {
  const metaCPA = c._metaCount > 0 ? c.metaCPA / c._metaCount : 0;

  if (c.leads === 0) {
    return { cliente: c.cliente, leads: 0, cpl: 0, status: 'sem-dados' };
  }

  const cpl = parseFloat((c.investimento / c.leads).toFixed(2));

  let status = 'verde';
  if (metaCPA > 0) {
    if (cpl > metaCPA)            status = 'vermelho';
    else if (cpl > metaCPA * 0.8) status = 'amarelo';
  }

  return { cliente: c.cliente, leads: c.leads, cpl, status };
});

const ordem = { vermelho: 0, amarelo: 1, verde: 2, 'sem-dados': 3 };
resultado.sort((a, b) => (ordem[a.status] ?? 9) - (ordem[b.status] ?? 9));

if (gestorFiltro && resultado.length === 0) {
  return [{ json: {
    status: 'ok', totalClientes: 0, data: [],
    aviso: `Nenhum cliente encontrado para o gestor "${gestorFiltro}". Verifique o nome na planilha.`,
    geradoEm: new Date().toISOString(), fromCache: false
  }}];
}

const payload = {
  status: 'ok',
  totalClientes: resultado.length,
  data: resultado,
  geradoEm: new Date().toISOString(),
  fromCache: false,
};

cache.ts = Date.now();
cache.payload = payload;

return [{ json: payload }];
